// Progress event types
export interface ProgressEvent {
  id: string;
  type: 'provisioning' | 'deployment';
  step: string;
  status: 'pending' | 'running' | 'completed' | 'failed';
  message: string;
  progress?: number;
}

export interface LogStreamEvent {
  id: string;
  type: 'stdout' | 'stderr';
  data: string;
  timestamp: number;
}

// API result types
export interface ApiResult<T = any> {
  success: boolean;
  data?: T;
  error?: string;
}

// Keychain access types
export enum KeychainErrorType {
  PERMISSION_DENIED = 'PERMISSION_DENIED',
  NOT_AVAILABLE = 'NOT_AVAILABLE',
  UNKNOWN_ERROR = 'UNKNOWN_ERROR',
}

export interface KeychainAccessResult {
  hasAccess: boolean;
  errorType?: KeychainErrorType;
  errorMessage?: string;
}

export type HealthStatus = 'healthy' | 'warning' | 'critical' | 'unknown';
export type AlertLevel = 'info' | 'warning' | 'critical';

export interface ServerHealthIndicator {
  key: string;
  label: string;
  level: 'ok' | 'warning' | 'critical';
  value: string;
  hint?: string;
}

export interface ServerAlert {
  id: string;
  level: AlertLevel;
  title: string;
  description?: string;
  actionLabel?: string;
}

export interface ServerMetrics {
  timestamp: number;
  health: {
    status: HealthStatus;
    score: number;
    summary: string;
    indicators: ServerHealthIndicator[];
  };
  system: {
    uptime: number;
    hostname?: string | null;
    os?: string | null;
    kernel?: string | null;
    loadAverage: {
      one: number | null;
      five: number | null;
      fifteen: number | null;
    };
    processCount?: number | null;
  };
  cpu: {
    usage: number;
    cores: number;
    model?: string | null;
    frequencyGHz?: number | null;
  };
  memory: {
    total: number;
    used: number;
    free: number;
    available: number;
    usagePercent: number;
    swapTotal: number | null;
    swapUsed: number | null;
    swapUsagePercent: number | null;
  };
  disk: {
    total: number;
    used: number;
    free: number;
    usagePercent: number;
    readBytes: number;
    writeBytes: number;
    rootDevice?: string | null;
    mounts: Array<{
      device: string;
      filesystem: string;
      mountpoint: string;
      total: number;
      used: number;
      available: number;
      usagePercent: number;
    }>;
  };
  network: {
    rxBytes: number;
    txBytes: number;
    rxPackets: number;
    txPackets: number;
    interfaces: Array<{
      name: string;
      rxBytes: number;
      txBytes: number;
      rxPackets: number;
      txPackets: number;
      speedMbps?: number | null;
    }>;
  };
  alerts: ServerAlert[];
}

/**
 * Quick metrics - essential data for dashboard cards.
 * Fetched first in progressive loading for instant UI feedback.
 */
export interface QuickMetrics {
  timestamp: number;
  cpu: {
    usage: number;
    cores: number;
  };
  memory: {
    total: number;
    used: number;
    usagePercent: number;
  };
  disk: {
    total: number;
    used: number;
    free: number;
    usagePercent: number;
    readBytes: number;
    writeBytes: number;
  };
  network: {
    rxBytes: number;
    txBytes: number;
  };
}

export interface SSHKeyInfo {
  path: string;
  fingerprint: string;
  type: string;
  comment?: string;
  created?: Date;
}

export interface CronJob {
  lineNumber: number;
  raw: string;
  schedule: string;
  command: string;
  isActive: boolean;
  isMacro: boolean;
  jobSignature: string;
  cronId: string | null;
  name: string | null;
  description: string | null;
  type: string | null;
  createdBy: string | null;
  supportsScheduleEdit: boolean;
  owner: 'user' | 'root';
}

export interface GitConnectionStatus {
  isConfigured: boolean;
  username?: string;
  keyPath?: string;
  rawOutput: string;
}

export interface ServerSSHKeyInfo {
  name: string;
  path: string;
  fingerprint?: string;
  type?: string;
}

export interface GitHubRepository {
  id: number;
  name: string;
  fullName: string;
  full_name: string;
  url: string;
  sshUrl: string;
  defaultBranch: string;
  default_branch: string;
  isPrivate: boolean;
  private: boolean;
  description?: string | null;
}

export interface FrameworkDetection {
  framework: 'nextjs' | 'react' | 'vue' | 'express' | 'fastify' | 'nestjs' | 'node' | 'unknown';
  detected: boolean;
  port?: number;
  packageManager?: 'npm' | 'yarn' | 'pnpm';
  buildCommand?: string; // Detected from package.json scripts
  startCommand?: string; // Detected from package.json scripts
}

export interface ServiceDeploymentResult {
  deploymentId: string;
  appName: string;
  port: number;
  url: string;
  status: 'running' | 'succeeded' | 'failed';
}

export interface SSHPublicKey {
  path: string;
  filename: string;
}

export interface GitHubAuthStatus {
  isAuthenticated: boolean;
  username?: string;
  protocol?: string;
}

export interface GitAccountConnection {
  appName: string;
  repository: string;
  branch: string;
}

export interface GitAccount {
  id: string;
  provider: 'github' | 'gitlab';
  alias: string;
  username: string;
  email?: string | null;
  avatarUrl?: string | null;
  scopes: string[];
  hostAlias: string;
  sshKeyPath?: string | null;
  isDefault: boolean;
  status: 'active' | 'revoked';
  createdAt: number;
  lastUsedAt?: number | null;
  connectedApps: GitAccountConnection[];
}

export interface GitAccountMapping {
  gitAccountId: string;
  accountAlias: string;
  accountUsername: string;
  provider: 'github' | 'gitlab';
  serverId: string;
  appName: string;
  repository: string;
  branch: string;
}

export interface GitAccountStatusResult {
  isValid: boolean;
  accountInfo?: {
    username: string;
    email?: string | null;
    avatarUrl?: string | null;
  };
  error?: string;
}

export interface CommandLog {
  id: string;
  server_id: string;
  command: string;
  executed_at: number;
  exit_code: number | null;
  stdout: string | null;
  stderr: string | null;
}

export interface NetworkInterface {
  interface: string;
  type: string;
  ipAddress: string;
  purpose: string;
}

export interface DNSLookupResult {
  domain: string;
  addresses: string[];
  resolvedAt: number;
}

export interface InstalledPackage {
  name: string;
  version: string;
  architecture: string;
}

export interface PortAvailability {
  available: boolean;
  port: number;
  usedBy?: {
    appName: string;
    pid: number;
    processName: string | null;
    cwd: string | null;
  };
}

export interface TemplateDeploymentResult {
  url: string;
  port: number;
  docsPath?: string;
  docsContent?: string;
}

